#!/usr/bin/env python3
from __future__ import annotations
import os
import sys
import hashlib
import time
from typing import List, Dict, Optional, Tuple

MINIGIT_DIR = ".minigit"
OBJECTS_DIR = os.path.join(MINIGIT_DIR, "objects")
INDEX_FILE = os.path.join(MINIGIT_DIR, "index")
HEAD_FILE = os.path.join(MINIGIT_DIR, "HEAD")


def sha1(data: bytes) -> str:
    return hashlib.sha1(data).hexdigest()


def safe_mkdir(dirname: str) -> None:
    if not os.path.isdir(dirname):
        os.makedirs(dirname)


def read_index() -> List[str]:
    try:
        with open(INDEX_FILE, "r") as f:
            return [line.strip() for line in f if line.strip()]
    except FileNotFoundError:
        return []


def write_index(files: List[str]) -> None:
    with open(INDEX_FILE, "w") as f:
        for filename in files:
            f.write(filename + "\n")


def get_head() -> Optional[str]:
    try:
        with open(HEAD_FILE, "r") as f:
            return f.read().strip()
    except FileNotFoundError:
        return None


def set_head(commit_hash: str) -> None:
    with open(HEAD_FILE, "w") as f:
        f.write(commit_hash + "\n")


def store_object(data: bytes) -> str:
    obj_hash = sha1(data)
    obj_path = os.path.join(OBJECTS_DIR, obj_hash)
    if not os.path.isfile(obj_path):
        with open(obj_path, "wb") as f:
            f.write(data)
    return obj_hash


def read_object(obj_hash: str) -> bytes:
    obj_path = os.path.join(OBJECTS_DIR, obj_hash)
    with open(obj_path, "rb") as f:
        return f.read()


def init() -> None:
    if os.path.isdir(MINIGIT_DIR):
        print("Repository already initialized.")
        sys.exit(1)
    safe_mkdir(OBJECTS_DIR)
    with open(INDEX_FILE, "w"):
        pass
    with open(HEAD_FILE, "w"):
        pass
    print("Initialized empty minigit repository in .minigit/")


def add(files: List[str]) -> None:
    index = set(read_index())
    for filename in files:
        if not os.path.isfile(filename):
            print(f"fatal: pathspec '{filename}' did not match any files")
            sys.exit(1)
        index.add(filename)
    write_index(sorted(index))


def hash_blob(filename: str) -> str:
    with open(filename, "rb") as f:
        data = f.read()
    blob_data = f"blob\n{filename}\n".encode() + data
    return store_object(blob_data)


def store_commit(
    parent: Optional[str],
    files: List[str],
    file_blobs: Dict[str, str],
    message: str,
    timestamp: int,
) -> str:
    header = "commit\n"
    parent_line = f"parent {parent}\n" if parent else ""
    time_line = f"time {timestamp}\n"
    files_lines = "".join([f"file {f} {file_blobs[f]}\n" for f in sorted(files)])
    message_line = f"\n{message}\n"
    commit_content = f"{header}{parent_line}{time_line}{files_lines}{message_line}".encode()
    return store_object(commit_content)


def parse_commit(commit_data: bytes) -> Tuple[Optional[str], int, Dict[str, str], str]:
    lines = commit_data.decode().splitlines()
    parent: Optional[str] = None
    timestamp: int = 0
    files: Dict[str, str] = {}
    i = 0
    while i < len(lines):
        line = lines[i]
        if line == "commit":
            i += 1
            continue
        elif line.startswith("parent "):
            parent = line.split(" ", 1)[1]
        elif line.startswith("time "):
            timestamp = int(line.split(" ", 1)[1])
        elif line.startswith("file "):
            _, fname, hsh = line.split(" ", 2)
            files[fname] = hsh
        elif line == "":
            break
        i += 1
    # message after blank line
    message = "\n".join(lines[i + 1 :])
    return parent, timestamp, files, message.strip()


def commit(message: str) -> None:
    files = read_index()
    if not files:
        print("nothing to commit")
        sys.exit(1)
    blobs: Dict[str, str] = {}
    for filename in files:
        if not os.path.isfile(filename):
            print(f"fatal: file '{filename}' does not exist")
            sys.exit(1)
        blobs[filename] = hash_blob(filename)
    parent = get_head()
    timestamp = int(time.time())
    commit_hash = store_commit(parent, files, blobs, message, timestamp)
    set_head(commit_hash)
    print(f"Committed as {commit_hash}")


def log() -> None:
    commit_hash = get_head()
    if not commit_hash:
        print("No commits yet.")
        return
    while commit_hash:
        commit_data = read_object(commit_hash)
        parent, timestamp, files, message = parse_commit(commit_data)
        print(f"commit {commit_hash}")
        print(f"Date: {time.strftime('%c', time.localtime(timestamp))}")
        print(f"\n    {message}\n")
        commit_hash = parent


def checkout(commit_hash: str) -> None:
    # Ensure commit exists
    try:
        commit_data = read_object(commit_hash)
    except FileNotFoundError:
        print(f"fatal: unknown commit {commit_hash}")
        sys.exit(1)
    _, _, files, _ = parse_commit(commit_data)
    for fname, hsh in files.items():
        blob_data = read_object(hsh)
        # Skip "blob\nfname\n", write only the file content
        header = f"blob\n{fname}\n".encode()
        if not blob_data.startswith(header):
            print(f"corrupt blob for {fname}")
            sys.exit(1)
        content = blob_data[len(header) :]
        with open(fname, "wb") as f:
            f.write(content)
    set_head(commit_hash)
    write_index(sorted(files.keys()))
    print(f"Checked out commit {commit_hash}")


def status() -> None:
    index = set(read_index())
    if not index:
        print("No files added")
        return
    for fname in sorted(index):
        print(fname)


def usage() -> None:
    print(
        "Usage: minigit [init|add|commit|log|checkout|status] [args...]"
    )
    sys.exit(1)


def main(argv: List[str]) -> None:
    if not argv:
        usage()
    cmd = argv[0]
    if cmd == "init":
        init()
    elif cmd == "add":
        if len(argv) < 2:
            print("add: missing operand")
            sys.exit(1)
        add(argv[1:])
    elif cmd == "commit":
        if len(argv) < 2:
            print("commit: missing message")
            sys.exit(1)
        message = argv[1]
        commit(message)
    elif cmd == "log":
        log()
    elif cmd == "checkout":
        if len(argv) < 2:
            print("checkout: missing commit hash")
            sys.exit(1)
        checkout(argv[1])
    elif cmd == "status":
        status()
    else:
        usage()


if __name__ == "__main__":
    main(sys.argv[1:])
```

